def create_html_paragraph(text):
    return f"<p>{text}</p>"

def sanitize_html(text):
    replacements = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;'
    }
    for char, escape in replacements.items():
        text = text.replace(char, escape)
    return text

turn3_code:
BLOG_FORMAT = "<h2>{headline}</h2><div>{text}</div>"

def create_html_paragraph(text):
    return f"<p>{text}</p>"

def sanitize_html(text):
    replacements = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;'
    }
    for char, escape in replacements.items():
        text = text.replace(char, escape)
    return text

def display_blog_entry(headline, text):
    sanitized_headline = sanitize_html(headline)
    sanitized_text = sanitize_html(text)
    return BLOG_FORMAT.format(headline=sanitized_headline, text=sanitized_text)

BLOG_FORMAT = "<h2>{headline}</h2><div>{text}</div>"

def html_format_message(title, content):
    return f"<h1>{title}</h1><p>{content}</p>"

def display_blog_entry(headline, text):
    return BLOG_FORMAT.format(headline=headline, text=text)

turn1_code:
import html

BLOG_FORMAT = "<h2>{headline}</h2><div>{text}</div>"

def display_blog_entry(headline: str, text: str) -> str:
    sanitized_headline = html.escape(headline)
    sanitized_text = html.escape(text)
    return BLOG_FORMAT.format(headline=sanitized_headline, text=sanitized_text)
